import java.util.*;class SortStackRec{static void sort(Stack<Integer>s){if(!s.isEmpty()){int x=s.pop();sort(s);ins(s,x);}}static void ins(Stack<Integer>s,int x){if(s.isEmpty()||s.peek()<=x){s.push(x);return;}int t=s.pop();ins(s,x);s.push(t);}public static void main(String[]a){Stack<Integer>s=new Stack<>();s.push(3);s.push(1);s.push(2);sort(s);while(!s.isEmpty())System.out.print(s.pop()+" ");}}